    protected static final MixinDirector INSTANCE;
    static {
        try {
            INSTANCE = new MixinDirector();
        } catch (IOException e) {
            throw new RuntimeException(e);
        }
    }
    ClassReader reader;
    ClassWriter writer;
    private MixinDirector( String refName ) throws IOException {
        TerrainSlabsMixinPlugin.LOGGER.info( "Attempting to find class: {}", refName );
        this.reader = new ClassReader( refName );
        this.writer = new ClassWriter( reader, 0 );
    }

    private MixinDirector() throws IOException {
        this.reader = new ClassReader( clazz, 0, clazz.length );
        this.writer = new ClassWriter( reader, 0 );
    }

    protected void define( String outputName ) {
        define( outputName, false );
    }
    protected void define( String outputName, boolean printDebug ) {
        PlatformASMHooks.defineClass( outputName, inscribeTargets( outputName ) );

        if ( printDebug ) {
            ClassReader classReader = new ClassReader( inscribeTargets( outputName ) );
            PrintWriter printWriter = new PrintWriter( System.out );
            TraceClassVisitor traceClassVisitor = new TraceClassVisitor( printWriter );
            ClassVisitor testVisitor = new ClassVisitor( ASM5, traceClassVisitor ) {};
            classReader.accept( testVisitor, 0 );
        }
    }

    protected static List<String> getTargets() {
        ClassCacheAccess.getCacheAsList().forEach( TerrainSlabsMixinPlugin.LOGGER::info );
        return ClassCacheAccess.getCacheAsList();
    }

    private byte[] inscribeTargets( String outputName ) {
        ClassVisitor classCopier = new AnnotationModifier( getTargets(), MIXIN_DESCRIPTOR, outputName, writer );
        reader.accept( classCopier, 0 );

//        byte[] code = writer.toByteArray();
//        StringBuilder output = new StringBuilder( "[" + code[0] );
//        for ( int i = 1; i < code.length; i++ ) {
//            output.append(", ").append( code[i] );
//        }
//        TerrainSlabsMixinPlugin.LOGGER.info( output.append( "]" ).toString() );

        return writer.toByteArray();
    }

    private static class AnnotationModifier extends ClassVisitor {
        private final List<String> targets;
        private final String annotationDescriptor;
        private final String outputName;
        public final ClassVisitor classVisitor;

        protected AnnotationModifier(List<String> targets, String descriptor, String outputName, ClassVisitor classVisitor ) {
            super( ASM5 );
            this.targets = targets;
            this.annotationDescriptor = descriptor;
            this.outputName = outputName;
            this.classVisitor = classVisitor;
            super.cv = new ClassNode( ASM5 );
        }

        @Override
        public void visit( int version, int access, String name, String signature, String superName, String[] interfaces ) {
            super.visit(version, access, outputName.replace( ".", "/" ), signature, superName, interfaces);
            AnnotationNode node = (AnnotationNode) super.cv.visitAnnotation( annotationDescriptor, false );
            Annotations.setValue( node, "priority", 1200 );
            Annotations.setValue( node, "refmap", false );
            Annotations.setValue( node, "targets", new ArrayList<>( targets ) );
        }

        @Override
        public AnnotationVisitor visitAnnotation( String descriptor, boolean visible ) {
            if ( !descriptor.equals( annotationDescriptor ) ) {
                return super.visitAnnotation( descriptor, visible );
            }
            return null;
        }

        @Override
        public void visitEnd() {
            super.visitEnd();
            ( (ClassNode) super.cv ).accept( classVisitor );
        }
    }
